const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) return true;
  if (!problem.tags || !Array.isArray(problem.tags)) return false;
  const problemTags = problem.tags.map((t) => String(t).toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Load problems from data file, cache in memory.
 * @returns {Array<Object>} problems
 */
function loadProblems() {
  if (cachedProblems) {
    return cachedProblems;
  }
  const dataPath = path.join(__dirname, '..', '..', '..', 'data', 'problems.json');
  const raw = fs.readFileSync(dataPath, 'utf8');
  cachedProblems = JSON.parse(raw);
  return cachedProblems;
}

/**
 * Aggregate component statistics for a problem.
 * @param {Object} problem
 * @returns {Object} componentStats
 */
function aggregateComponentStats(problem) {
  const componentStats = {
    languages: {},
    statusCounts: {},
    maxPoints: 0
  };

  if (!problem.components || !Array.isArray(problem.components)) {
    return componentStats;
  }

  for (const comp of problem.components) {
    // Count languages
    if (comp.language) {
      const lang = String(comp.language);
      componentStats.languages[lang] = (componentStats.languages[lang] || 0) + 1;
    }
    // Count statuses
    if (comp.status) {
      const status = String(comp.status);
      componentStats.statusCounts[status] = (componentStats.statusCounts[status] || 0) + 1;
    }
    // Track max points
    if (typeof comp.points === 'number' && comp.points > componentStats.maxPoints) {
      componentStats.maxPoints = comp.points;
    }
  }

  return componentStats;
}

